using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments =
    [
        new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and information systems." },
        new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Study of numbers, structures, and patterns." },
        new() { Id = 3, Name = "Physics", Code = "PHYS", Description = "Study of matter, energy, and the fundamental forces of nature." },
        new() { Id = 4, Name = "English", Code = "ENG", Description = "Study of literature, writing, and language." },
        new() { Id = 5, Name = "History", Code = "HIST", Description = "Study of past events and civilizations." },
    ];

    private readonly List<Course> _courses =
    [
        new() { Id = 1, DepartmentId = 1, CourseCode = "CS 101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using C#. Topics include variables, control flow, functions, and object-oriented basics.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience in software engineering and computer science education. She specializes in programming languages and compiler design.", IsFeatured = true },
        new() { Id = 2, DepartmentId = 1, CourseCode = "CS 201", Title = "Data Structures & Algorithms", Description = "Study of fundamental data structures (arrays, linked lists, trees, graphs) and algorithm design techniques (sorting, searching, dynamic programming).", Credits = 4, Schedule = "Tue/Thu 10:30–11:45 AM", InstructorName = "Dr. James Rodriguez", InstructorBio = "Dr. Rodriguez is an expert in algorithm optimization and computational complexity. He has published over 40 papers in top conferences.", IsFeatured = true },
        new() { Id = 3, DepartmentId = 1, CourseCode = "CS 310", Title = "Database Systems", Description = "Relational database design, SQL, normalization, indexing, and transaction management.", Credits = 3, Schedule = "Mon/Wed 2:00–3:15 PM", InstructorName = "Dr. Maria Lopez", InstructorBio = "Dr. Lopez specializes in distributed databases and data engineering. Previously worked at major tech companies on large-scale data systems.", IsFeatured = false },
        new() { Id = 4, DepartmentId = 2, CourseCode = "MATH 151", Title = "Calculus I", Description = "Limits, derivatives, integrals, and the fundamental theorem of calculus.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim is an award-winning educator with expertise in analysis and applied mathematics.", IsFeatured = true },
        new() { Id = 5, DepartmentId = 2, CourseCode = "MATH 250", Title = "Linear Algebra", Description = "Vector spaces, matrices, linear transformations, eigenvalues, and applications.", Credits = 3, Schedule = "Tue/Thu 1:00–2:15 PM", InstructorName = "Dr. Emily Park", InstructorBio = "Dr. Park researches numerical linear algebra and has contributed to several open-source mathematics libraries.", IsFeatured = false },
        new() { Id = 6, DepartmentId = 3, CourseCode = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Includes laboratory sessions.", Credits = 4, Schedule = "Tue/Thu 9:00–10:15 AM + Lab Fri 1:00–3:00 PM", InstructorName = "Dr. Alan Foster", InstructorBio = "Dr. Foster is an experimental physicist specializing in condensed matter physics and science pedagogy.", IsFeatured = false },
        new() { Id = 7, DepartmentId = 3, CourseCode = "PHYS 220", Title = "Electromagnetism", Description = "Electric fields, magnetic fields, Maxwell's equations, and electromagnetic waves.", Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", InstructorName = "Dr. Priya Sharma", InstructorBio = "Dr. Sharma's research focuses on photonics and electromagnetic theory. She is a Fellow of the American Physical Society.", IsFeatured = true },
        new() { Id = 8, DepartmentId = 4, CourseCode = "ENG 101", Title = "College Writing", Description = "Develop critical reading, thinking, and writing skills through essay composition and revision.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", InstructorName = "Prof. David Wright", InstructorBio = "Prof. Wright is a published author and writing instructor with 20 years of experience teaching composition.", IsFeatured = false },
        new() { Id = 9, DepartmentId = 4, CourseCode = "ENG 240", Title = "American Literature", Description = "Survey of American literature from the colonial period to the present.", Credits = 3, Schedule = "Tue/Thu 3:00–4:15 PM", InstructorName = "Dr. Angela Morrison", InstructorBio = "Dr. Morrison specializes in 20th-century American fiction and has authored two books on the Harlem Renaissance.", IsFeatured = false },
        new() { Id = 10, DepartmentId = 5, CourseCode = "HIST 110", Title = "World Civilizations", Description = "A global survey of major civilizations from antiquity to the modern era.", Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:15 PM", InstructorName = "Dr. Thomas Grant", InstructorBio = "Dr. Grant is a historian specializing in comparative civilizations and cross-cultural exchange.", IsFeatured = true },
    ];

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetAllCourses() => _courses;

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public List<Course> GetCoursesByDepartment(int departmentId) =>
        _courses.Where(c => c.DepartmentId == departmentId).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> SearchCourses(string? searchTerm, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.CourseCode.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }
}

