@page "/courses"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>Browse Courses</PageTitle>

<h1>Browse Courses</h1>

<form method="get" action="/courses" class="row g-3 mb-4">
    <div class="col-md-6">
        <input type="text" name="search" value="@Search" class="form-control" placeholder="Search courses..." />
    </div>
    <div class="col-md-4">
        <select name="departmentId" class="form-select">
            <option value="">All Departments</option>
            @foreach (var dept in Catalog.GetDepartments())
            {
                <option value="@dept.Id" selected="@(DepartmentId == dept.Id)">@dept.Code – @dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-2">
        <button type="submit" class="btn btn-primary w-100">Search</button>
    </div>
</form>

@{
    var courses = Catalog.SearchCourses(Search, DepartmentId);
}

@if (courses.Count == 0)
{
    <p class="text-muted">No courses found matching your criteria.</p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Code</th>
                <th>Title</th>
                <th>Department</th>
                <th>Credits</th>
                <th>Instructor</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in courses)
            {
                var dept = Catalog.GetDepartment(course.DepartmentId);
                <tr>
                    <td>@course.CourseCode</td>
                    <td>@course.Title</td>
                    <td>@dept?.Name</td>
                    <td>@course.Credits</td>
                    <td>@course.InstructorName</td>
                    <td><a href="/courses/@course.Id" class="btn btn-outline-primary btn-sm">Details</a></td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [SupplyParameterFromQuery]
    public string? Search { get; set; }

    [SupplyParameterFromQuery]
    public int? DepartmentId { get; set; }
}

@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

@{
    var course = Catalog.GetCourse(Id);
}

@if (course is null)
{
    <PageTitle>Course Not Found</PageTitle>
    <h1>Course Not Found</h1>
    <p>The requested course does not exist.</p>
    <a href="/courses">Back to course list</a>
}
else
{
    var dept = Catalog.GetDepartment(course.DepartmentId);

    <PageTitle>@course.CourseCode – @course.Title</PageTitle>

    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="/courses?departmentId=@course.DepartmentId">@dept?.Name</a></li>
            <li class="breadcrumb-item active">@course.CourseCode</li>
        </ol>
    </nav>

    <h1>@course.CourseCode – @course.Title</h1>

    <div class="row mt-4">
        <div class="col-md-8">
            <h2>Description</h2>
            <p>@course.Description</p>

            <h2>Instructor</h2>
            <h4>@course.InstructorName</h4>
            <p>@course.InstructorBio</p>
        </div>
        <div class="col-md-4">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">Course Details</h5>
                    <dl>
                        <dt>Department</dt>
                        <dd>@dept?.Name</dd>

                        <dt>Credits</dt>
                        <dd>@course.Credits</dd>

                        <dt>Schedule</dt>
                        <dd>@course.Schedule</dd>
                    </dl>
                    <a href="/enroll?courseId=@course.Id" class="btn btn-success w-100">Request Enrollment</a>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter]
    public int Id { get; set; }
}

@page "/enroll"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p>Submit a request to enroll in a course. All fields are required.</p>

@if (Submitted)
{
    var selectedCourse = Catalog.GetCourse(Model.CourseId);
    <div class="alert alert-success">
        <h4>Request Submitted!</h4>
        <p>Thank you, <strong>@Model.StudentName</strong> (ID: @Model.StudentId). Your enrollment request for
            <strong>@selectedCourse?.CourseCode – @selectedCourse?.Title</strong> has been received.</p>
        <a href="/enroll" class="btn btn-outline-success">Submit Another</a>
        <a href="/courses" class="btn btn-outline-primary ms-2">Browse Courses</a>
    </div>
}
else
{
    <form method="post" action="/enroll" class="col-md-8">
        <AntiforgeryToken />

        <div class="mb-3">
            <label for="studentName" class="form-label">Full Name</label>
            <input type="text" id="studentName" name="Model.StudentName" value="@Model.StudentName" class="form-control" required />
            @if (Errors.ContainsKey(nameof(Model.StudentName)))
            {
                <div class="text-danger">@Errors[nameof(Model.StudentName)]</div>
            }
        </div>

        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID</label>
            <input type="text" id="studentId" name="Model.StudentId" value="@Model.StudentId" class="form-control" required />
            @if (Errors.ContainsKey(nameof(Model.StudentId)))
            {
                <div class="text-danger">@Errors[nameof(Model.StudentId)]</div>
            }
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course</label>
            <select id="courseId" name="Model.CourseId" class="form-select" required>
                <option value="0">-- Select a course --</option>
                @foreach (var course in Catalog.GetAllCourses())
                {
                    <option value="@course.Id" selected="@(Model.CourseId == course.Id)">@course.CourseCode – @course.Title</option>
                }
            </select>
            @if (Errors.ContainsKey(nameof(Model.CourseId)))
            {
                <div class="text-danger">@Errors[nameof(Model.CourseId)]</div>
            }
        </div>

        <button type="submit" class="btn btn-success">Submit Enrollment Request</button>
        <a href="/courses" class="btn btn-outline-secondary ms-2">Cancel</a>
    </form>
}

@code {
    [SupplyParameterFromForm]
    public EnrollmentRequest Model { get; set; } = new();

    [SupplyParameterFromQuery]
    public int? CourseId { get; set; }

    private bool Submitted { get; set; }
    private Dictionary<string, string> Errors { get; set; } = new();

    protected override void OnInitialized()
    {
        if (CourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = CourseId.Value;
        }
    }

    protected override void OnParametersSet()
    {
        // Check if this is a POST (form submission)
        if (Model.StudentName != string.Empty || Model.StudentId != string.Empty || Model.CourseId > 0)
        {
            // Validate
            var validationResults = new List<System.ComponentModel.DataAnnotations.ValidationResult>();
            var context = new System.ComponentModel.DataAnnotations.ValidationContext(Model);
            if (System.ComponentModel.DataAnnotations.Validator.TryValidateObject(Model, context, validationResults, true))
            {
                Submitted = true;
            }
            else
            {
                foreach (var result in validationResults)
                {
                    foreach (var member in result.MemberNames)
                    {
                        Errors.TryAdd(member, result.ErrorMessage ?? "Invalid");
                    }
                }
            }
        }
    }
}

