        <AntiforgeryToken />

        <div class="mb-3">
            <label for="studentName" class="form-label">Full Name</label>
            <input type="text" id="studentName" name="Model.StudentName" value="@(Model?.StudentName)" class="form-control" required />
            @if (Errors.ContainsKey(nameof(EnrollmentRequest.StudentName)))
            {
                <div class="text-danger">@Errors[nameof(EnrollmentRequest.StudentName)]</div>
            }
        </div>

        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID</label>
            <input type="text" id="studentId" name="Model.StudentId" value="@(Model?.StudentId)" class="form-control" required />
            @if (Errors.ContainsKey(nameof(EnrollmentRequest.StudentId)))
            {
                <div class="text-danger">@Errors[nameof(EnrollmentRequest.StudentId)]</div>
            }
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course</label>
            <select id="courseId" name="Model.CourseId" class="form-select" required>
                <option value="0">-- Select a course --</option>
                @foreach (var course in Catalog.GetAllCourses())
